<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  body{font-family:Arial,sans-serif;margin:20px;}
  form div{margin-bottom:10px;}
  #expenses{margin-top:20px;border-collapse:collapse;width:100%;}
  #expenses th, #expenses td{border:1px solid #ccc;padding:8px;text-align:left;}
  .expense-row{background:#f9f9f9;}
  .exp-del{color:red;cursor:pointer;background:none;border:none;font-size:0.9em;}
  #summary{margin-top:20px;}
  .cat-total{display:inline-block;margin-right:15px;}
  #form-error{color:red;}
</style>
</head>
<body>

<h1>Expense Tracker</h1>

<form id="expense-form">
  <div>
    <label>Amount: <input type="number" step="0.01" id="amount" required></label>
  </div>
  <div>
    <label>Category:
      <select id="category">
        <option value="groceries">Groceries</option>
        <option value="transport">Transport</option>
        <option value="bills">Bills</option>
        <option value="fun">Fun</option>
      </select>
    </label>
  </div>
  <div>
    <label>Date: <input type="date" id="date" required></label>
  </div>
  <div>
    <label>Note: <input type="text" id="note"></label>
  </div>
  <button type="submit" id="add-expense">Add Expense</button>
  <div id="form-error"></div>
</form>

<h2>Filters</h2>
<div>
  <label>Category:
    <select id="filter-category">
      <option value="all">All</option>
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>
  </label>
  <label>From: <input type="date" id="filter-from"></label>
  <label>To: <input type="date" id="filter-to"></label>
</div>

<table id="expenses">
  <thead>
    <tr><th>Amount</th><th>Category</th><th>Date</th><th>Note</th><th></th></tr>
  </thead>
  <tbody id="expense-list"></tbody>
</table>

<div id="summary">
  <h3>Total: $<span id="total">0.00</span></h3>
  <div class="cat-total" data-cat="groceries">Groceries: $<span>0.00</span></div>
  <div class="cat-total" data-cat="transport">Transport: $<span>0.00</span></div>
  <div class="cat-total" data-cat="bills">Bills: $<span>0.00</span></div>
  <div class="cat-total" data-cat="fun">Fun: $<span>0.00</span></div>
</div>

<script>
(function(){
  const form = document.getElementById('expense-form');
  const amountInput = document.getElementById('amount');
  const categorySelect = document.getElementById('category');
  const dateInput = document.getElementById('date');
  const noteInput = document.getElementById('note');
  const errorDiv = document.getElementById('form-error');

  const expenseList = document.getElementById('expense-list');
  const totalSpan = document.getElementById('total');
  const catTotals = document.querySelectorAll('.cat-total span');

  const filterCategory = document.getElementById('filter-category');
  const filterFrom = document.getElementById('filter-from');
  const filterTo = document.getElementById('filter-to');

  let expenses = [];

  function save() {
    localStorage.setItem('expenses', JSON.stringify(expenses));
  }

  function load() {
    const data = localStorage.getItem('expenses');
    if (data) expenses = JSON.parse(data);
  }

  function formatAmt(n){ return Number(n).toFixed(2); }

  function renderList(){
    expenseList.innerHTML='';
    // newest first
    [...expenses].reverse().forEach(exp=>{
      const tr=document.createElement('tr');
      tr.className='expense-row';
      tr.dataset.id=exp.id;
      tr.dataset.cat=exp.category;
      tr.dataset.date=exp.date;

      tr.innerHTML=`<td>$${formatAmt(exp.amount)}</td>
                    <td>${exp.category}</td>
                    <td>${exp.date}</td>
                    <td>${exp.note||''}</td>
                    <td><button class="exp-del">✖</button></td>`;
      expenseList.appendChild(tr);
    });
  }

  function applyFilters(){
    const catVal=filterCategory.value;
    const from=filterFrom.value;
    const to=filterTo.value;

    let visibleCount=0;
    let totals={groceries:0,transport:0,bills:0,fun:0};

    document.querySelectorAll('.expense-row').forEach(row=>{
      const cat=row.dataset.cat;
      const date=row.dataset.date;
      let show=true;
      if(catVal!=='all' && cat!==catVal) show=false;
      if(from && date<from) show=false;
      if(to && date>to) show=false;
      row.style.display=show?'':'none';
      if(show){
        visibleCount++;
        totals[cat]+=parseFloat(row.cells[0].textContent.replace('$',''));
      }
    });

    totalSpan.textContent=formatAmt(Object.values(totals).reduce((a,b)=>a+b,0));
    catTotals.forEach(span=>{
      const cat=span.parentElement.dataset.cat;
      span.textContent=formatAmt(totals[cat]);
    });
  }

  form.addEventListener('submit',e=>{
    e.preventDefault();
    const amt=parseFloat(amountInput.value);
    const date=dateInput.value;
    if(isNaN(amt)||amt<=0||!date){
      errorDiv.textContent='Please enter a valid amount and date.';
      return;
    }
    errorDiv.textContent='';
    const exp={
      id:Date.now(),
      amount:amt,
      category:categorySelect.value,
      date,
      note:noteInput.value.trim()
    };
    expenses.push(exp);
    save();
    renderList();
    applyFilters();
    amountInput.value='';
  });

  expenseList.addEventListener('click',e=>{
    if(e.target.classList.contains('exp-del')){
      const id=parseInt(e.target.closest('.expense-row').dataset.id,10);
      expenses=expenses.filter(x=>x.id!==id);
      save();
      renderList();
      applyFilters();
    }
  });

  filterCategory.addEventListener('change',applyFilters);
  filterFrom.addEventListener('input',applyFilters);
  filterTo.addEventListener('input',applyFilters);

  load();
  renderList();
  applyFilters();
})();
</script>
</body>
</html>
